(3, 'easy', 'What is a database?', 'A collection of organized data', 'A programming language', 'A hardware device', 'A web browser', 'A collection of organized data', 'A database stores data in an organized way.'),
(3, 'easy', 'What does SQL stand for?', 'Structured Query Language', 'Simple Query List', 'System Query Logic', 'Standard Question Language', 'Structured Query Language', 'SQL stands for Structured Query Language.'),
(3, 'easy', 'Which SQL command is used to retrieve data?', 'INSERT', 'SELECT', 'UPDATE', 'DELETE', 'SELECT', 'SELECT is used to fetch records from a table.'),
