(3, 'easy', 'Which SQL command is used to change existing data?', 'UPDATE', 'CREATE', 'SELECT', 'GRANT', 'UPDATE', 'UPDATE modifies existing records.'),
(3, 'easy', 'Which SQL command removes data from a table?', 'DELETE', 'DROP', 'ALTER', 'JOIN', 'DELETE', 'DELETE removes rows from a table.'),
(3, 'easy', 'What is a table in a database?', 'A collection of rows and columns', 'A programming file', 'A network protocol', 'A sort method', 'A collection of rows and columns', 'A table stores data in rows and columns.'),
