(3, 'easy', 'What is a column also called?', 'Attribute', 'Tuple', 'Record', 'Index', 'Attribute', 'A column stores a specific field or attribute.'),
(3, 'easy', 'What is a primary key?', 'A unique identifier for each row', 'A foreign table', 'A duplicate value', 'A null value', 'A unique identifier for each row', 'Primary key uniquely identifies each record.'),
(3, 'easy', 'Can a primary key contain duplicate values?', 'Yes', 'No', 'Sometimes', 'Only if allowed', 'No', 'A primary key must be unique.'),
